import{_ as e,c as o,o as l,a1 as t}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"多管道與平台 | Clawdbot 教學","description":"學習如何設定和使用 Clawdbot 的多管道系統，包括 WhatsApp、Telegram、Slack、Discord、Google Chat、Signal、iMessage、LINE、WebChat、macOS、iOS 和 Android 平台。","frontmatter":{"title":"多管道與平台 | Clawdbot 教學","sidebarTitle":"接入常用通訊工具","subtitle":"多管道與平台","description":"學習如何設定和使用 Clawdbot 的多管道系統，包括 WhatsApp、Telegram、Slack、Discord、Google Chat、Signal、iMessage、LINE、WebChat、macOS、iOS 和 Android 平台。","tags":["channels","platforms","integration"],"order":60},"headers":[],"relativePath":"zh-tw/moltbot/moltbot/platforms/index.md","filePath":"zh-tw/moltbot/moltbot/platforms/index.md"}'),r={name:"zh-tw/moltbot/moltbot/platforms/index.md"};function i(s,a,n,h,d,g){return l(),o("div",null,[...a[0]||(a[0]=[t('<h1 id="多管道與平台" tabindex="-1">多管道與平台 <a class="header-anchor" href="#多管道與平台" aria-label="Permalink to &quot;多管道與平台&quot;">​</a></h1><p>Clawdbot 透過統一的 Gateway 控制平面，支援多種通訊管道和平台，讓你在熟悉的介面上與 AI 助理互動。</p><h2 id="章節概述" tabindex="-1">章節概述 <a class="header-anchor" href="#章節概述" aria-label="Permalink to &quot;章節概述&quot;">​</a></h2><p>本章節介紹 Clawdbot 支援的所有通訊管道和平台，包括即時通訊應用（WhatsApp、Telegram、Slack、Discord 等）、行動端節點（iOS、Android）和桌面應用（macOS）。學習如何設定這些管道，讓 AI 助理無縫融入你的日常工作流程。</p><h2 id="子頁面導覽" tabindex="-1">子頁面導覽 <a class="header-anchor" href="#子頁面導覽" aria-label="Permalink to &quot;子頁面導覽&quot;">​</a></h2><h3 id="管道概覽" tabindex="-1">管道概覽 <a class="header-anchor" href="#管道概覽" aria-label="Permalink to &quot;管道概覽&quot;">​</a></h3><ul><li><strong><a href="./channels-overview/">多管道系統概覽</a></strong> - 了解 Clawdbot 支援的所有通訊管道及其特點，掌握管道設定的基本概念。</li></ul><h3 id="即時通訊管道" tabindex="-1">即時通訊管道 <a class="header-anchor" href="#即時通訊管道" aria-label="Permalink to &quot;即時通訊管道&quot;">​</a></h3><ul><li><strong><a href="./whatsapp/">WhatsApp</a></strong> - 設定和使用 WhatsApp 管道（基於 Baileys），支援裝置連結和群組管理。</li><li><strong><a href="./telegram/">Telegram</a></strong> - 設定和使用 Telegram 管道（基於 grammY Bot API），設定 Bot Token 和 Webhook。</li><li><strong><a href="./slack/">Slack</a></strong> - 設定和使用 Slack 管道（基於 Bolt），整合到你的工作空間。</li><li><strong><a href="./discord/">Discord</a></strong> - 設定和使用 Discord 管道（基於 discord.js），支援伺服器和頻道。</li><li><strong><a href="./googlechat/">Google Chat</a></strong> - 設定和使用 Google Chat 管道，與 Google Workspace 整合。</li><li><strong><a href="./signal/">Signal</a></strong> - 設定和使用 Signal 管道（基於 signal-cli），保護隱私的通訊。</li><li><strong><a href="./imessage/">iMessage</a></strong> - 設定和使用 iMessage 管道（macOS 專屬），與 macOS 訊息應用整合。</li><li><strong><a href="./line/">LINE</a></strong> - 設定和使用 LINE 管道（Messaging API），與 LINE 使用者互動。</li></ul><h3 id="web-與原生應用" tabindex="-1">Web 與原生應用 <a class="header-anchor" href="#web-與原生應用" aria-label="Permalink to &quot;Web 與原生應用&quot;">​</a></h3><ul><li><strong><a href="./webchat/">WebChat 介面</a></strong> - 使用內建的 WebChat 介面與 AI 助理互動，無需設定外部管道。</li><li><strong><a href="./macos-app/">macOS 應用</a></strong> - 了解 macOS 選單列應用的功能，包括 Voice Wake、Talk Mode 和遠端控制。</li><li><strong><a href="./ios-node/">iOS 節點</a></strong> - 設定 iOS 節點以執行裝置本地操作（Camera、Canvas、Voice Wake）。</li><li><strong><a href="./android-node/">Android 節點</a></strong> - 設定 Android 節點以執行裝置本地操作（Camera、Canvas）。</li></ul><h2 id="學習路徑建議" tabindex="-1">學習路徑建議 <a class="header-anchor" href="#學習路徑建議" aria-label="Permalink to &quot;學習路徑建議&quot;">​</a></h2><p>根據你的使用場景，推薦以下學習順序：</p><h3 id="新手快速上手" tabindex="-1">新手快速上手 <a class="header-anchor" href="#新手快速上手" aria-label="Permalink to &quot;新手快速上手&quot;">​</a></h3><p>如果你是第一次使用 Clawdbot，建議按照以下順序學習：</p><ol><li><strong><a href="./channels-overview/">多管道系統概覽</a></strong> - 先了解整體架構和管道概念</li><li><strong><a href="./webchat/">WebChat 介面</a></strong> - 最簡單的方式，無需任何設定即可開始使用</li><li><strong>選擇一個常用管道</strong> - 根據你的日常習慣選擇： <ul><li>日常聊天 → <a href="./whatsapp/">WhatsApp</a> 或 <a href="./telegram/">Telegram</a></li><li>團隊協作 → <a href="./slack/">Slack</a> 或 <a href="./discord/">Discord</a></li><li>macOS 使用者 → <a href="./imessage/">iMessage</a></li></ul></li></ol><h3 id="行動端整合" tabindex="-1">行動端整合 <a class="header-anchor" href="#行動端整合" aria-label="Permalink to &quot;行動端整合&quot;">​</a></h3><p>如果你想在手機上使用 Clawdbot：</p><ol><li><strong><a href="./ios-node/">iOS 節點</a></strong> - 設定 iPhone/iPad 上的本地功能</li><li><strong><a href="./android-node/">Android 節點</a></strong> - 設定 Android 裝置上的本地功能</li><li><strong><a href="./macos-app/">macOS 應用</a></strong> - 使用 macOS 應用作為控制中心</li></ol><h3 id="企業級部署" tabindex="-1">企業級部署 <a class="header-anchor" href="#企業級部署" aria-label="Permalink to &quot;企業級部署&quot;">​</a></h3><p>如果你需要在團隊環境中部署：</p><ol><li><strong><a href="./slack/">Slack</a></strong> - 與團隊工作空間整合</li><li><strong><a href="./discord/">Discord</a></strong> - 建立社群伺服器</li><li><strong><a href="./googlechat/">Google Chat</a></strong> - 與 Google Workspace 整合</li></ol><h2 id="前置條件" tabindex="-1">前置條件 <a class="header-anchor" href="#前置條件" aria-label="Permalink to &quot;前置條件&quot;">​</a></h2><p>在開始學習本章節之前，建議先完成：</p><ul><li><strong><a href="./../start/getting-started/">快速開始</a></strong> - 完成 Clawdbot 的安裝和基礎設定</li><li><strong><a href="./../start/onboarding-wizard/">精靈式設定</a></strong> - 透過精靈完成 Gateway 和管道的基礎設定</li></ul><div class="tip custom-block"><p class="custom-block-title">提示</p><p>如果你已經完成了精靈式設定，一些管道可能已經自動設定好了。可以跳過重複的設定步驟，直接查看特定管道的進階功能。</p></div><h2 id="下一步指引" tabindex="-1">下一步指引 <a class="header-anchor" href="#下一步指引" aria-label="Permalink to &quot;下一步指引&quot;">​</a></h2><p>完成本章節的學習後，你可以繼續探索：</p><ul><li><strong><a href="./../advanced/models-auth/">AI 模型與驗證設定</a></strong> - 設定不同的 AI 模型提供商</li><li><strong><a href="./../advanced/session-management/">工作階段管理與多 Agent</a></strong> - 學習工作階段隔離和子 Agent 協作</li><li><strong><a href="./../advanced/tools-browser/">工具系統</a></strong> - 使用瀏覽器自動化、命令執行等工具</li></ul><h2 id="常見問題" tabindex="-1">常見問題 <a class="header-anchor" href="#常見問題" aria-label="Permalink to &quot;常見問題&quot;">​</a></h2><details class="details custom-block"><summary>我可以同時使用多個管道嗎？</summary><p>是的！Clawdbot 支援同時啟用多個管道。你可以在不同管道上接收和傳送訊息，所有訊息都透過統一的 Gateway 處理。</p></details><details class="details custom-block"><summary>哪個管道最推薦？</summary><p>這取決於你的使用場景：</p><ul><li><strong>WebChat</strong> - 最簡單，無需任何設定</li><li><strong>WhatsApp</strong> - 適合與朋友和家人聊天</li><li><strong>Telegram</strong> - Bot API 穩定，適合自動回覆</li><li><strong>Slack/Discord</strong> - 適合團隊協作</li></ul></details><details class="details custom-block"><summary>設定管道需要付費嗎？</summary><p>大多數管道本身是免費的，但部分管道可能有成本：</p><ul><li>WhatsApp Business API - 可能產生費用</li><li>Google Chat - 需要 Google Workspace 帳戶</li><li>其他管道 - 通常免費，只需申請 Bot Token</li></ul></details>',33)])])}const p=e(r,[["render",i]]);export{m as __pageData,p as default};
